## Backend - Tauri Event System

```rust
// src-tauri/src/main.rs
use tauri::{Manager, Window};
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use tokio::sync::Mutex;

#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct ProgressUpdate {
    pub id: String,
    pub progress: f32,
    pub status: String,
    pub message: Option<String>,
    pub timestamp: u64,
}

#[derive(Clone)]
pub struct ProgressManager {
    window: Arc<Mutex<Option<Window>>>,
}

impl ProgressManager {
    pub fn new() -> Self {
        Self {
            window: Arc::new(Mutex::new(None)),
        }
    }

    pub async fn set_window(&self, window: Window) {
        let mut w = self.window.lock().await;
        *w = Some(window);
    }

    pub async fn emit_progress(&self, update: ProgressUpdate) -> Result<(), String> {
        let window = self.window.lock().await;
        if let Some(ref w) = *window {
            w.emit("progress-update", &update)
                .map_err(|e| format!("Failed to emit progress: {}", e))?;
        }
        Ok(())
    }
}

#[tauri::command]
async fn start_progress_stream(
    window: Window,
    progress_manager: tauri::State<'_, ProgressManager>,
) -> Result<(), String> {
    progress_manager.set_window(window).await;
    Ok(())
}

fn main() {
    let progress_manager = ProgressManager::new();

    tauri::Builder::default()
        .manage(progress_manager)
        .invoke_handler(tauri::generate_handler![start_progress_stream])
        .setup(|app| {
            let window = app.get_window("main").unwrap();
            let progress_manager = app.state::<ProgressManager>();

            tauri::async_runtime::spawn(async move {
                progress_manager.set_window(window).await;
            });

            Ok(())
        })
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}
```

## Frontend - Progress Stream Service

```typescript
// src/lib/services/progressStream.ts
import { listen } from '@tauri-apps/api/event';
import { invoke } from '@tauri-apps/api/tauri';

export interface ProgressUpdate {
  id: string;
  progress: number;
  status: string;
  message?: string;
  timestamp: number;
}

export type ProgressCallback = (update: ProgressUpdate) => void;

class ProgressStreamService {
  private callbacks = new Map<string, ProgressCallback[]>();
  private isInitialized = false;
  private websocket: WebSocket | null = null;

  async initialize(): Promise<void> {
    if (this.isInitialized) return;

    try {
      // Try Tauri events first
      await invoke('start_progress_stream');
      await this.setupTauriListener();
      this.isInitialized = true;
    } catch (error) {
      // Fallback to WebSocket for web
      console.log('Tauri not available, using WebSocket fallback');
      this.setupWebSocketFallback();
    }
  }

  private async setupTauriListener(): Promise<void> {
    await listen<ProgressUpdate>('progress-update', (event) => {
      this.handleProgressUpdate(event.payload);
    });
  }

  private setupWebSocketFallback(): void {
    const wsUrl = `ws://${window.location.host}/ws/progress`;
    this.websocket = new WebSocket(wsUrl);

    this.websocket.onmessage = (event) => {
      try {
        const update: ProgressUpdate = JSON.parse(event.data);
        this.handleProgressUpdate(update);
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error);
      }
    };

    this.websocket.onclose = () => {
      // Reconnect after 3 seconds
      setTimeout(() => this.setupWebSocketFallback(), 3000);
    };
  }

  private handleProgressUpdate(update: ProgressUpdate): void {
    const callbacks = this.callbacks.get(update.id) || [];
    callbacks.forEach(callback => callback(update));
  }

  subscribe(id: string, callback: ProgressCallback): () => void {
    if (!this.callbacks.has(id)) {
      this.callbacks.set(id, []);
    }
    this.callbacks.get(id)!.push(callback);

    // Return unsubscribe function
    return () => {
      const callbacks = this.callbacks.get(id);
      if (callbacks) {
        const index = callbacks.indexOf(callback);
        if (index > -1) {
          callbacks.splice(index, 1);
        }
        if (callbacks.length === 0) {
          this.callbacks.delete(id);
        }
      }
    };
  }

  async emitProgress(update: ProgressUpdate): Promise<void> {
    if (this.websocket && this.websocket.readyState === WebSocket.OPEN) {
      this.websocket.send(JSON.stringify(update));
    }
  }
}

export const progressStream = new ProgressStreamService();
```

