  import { onMount, onDestroy } from 'svelte';
  import { progressStream, type ProgressUpdate } from '$lib/services/progressStream';

  export let messageId: string;
  export let content: string;
  export let isStreaming = false;

  let progress = 0;
  let status = '';
  let progressMessage = '';
  let unsubscribe: (() => void) | null = null;

  onMount(async () => {
    await progressStream.initialize();

    if (isStreaming) {
      unsubscribe = progressStream.subscribe(messageId, handleProgressUpdate);
    }
  });

  onDestroy(() => {
    if (unsubscribe) {
      unsubscribe();
    }
  });

  function handleProgressUpdate(update: ProgressUpdate) {
    progress = update.progress;
    status = update.status;
    progressMessage = update.message || '';

    // Stop streaming when complete
