import os
import json
import glob

class FavoritePersistence:
    """Handles saving and loading favorite status from data/gr* storage files."""

    def __init__(self, data_dir="data"):
        self.data_dir = data_dir
        self.favorite_files_pattern = os.path.join(data_dir, "gr*")

    def save_favorite_status(self, item_id, is_favorite):
        """Save favorite status for an item to the appropriate storage file."""
        # Find the appropriate gr* file (using gr1 as default if none exist)
        storage_file = self._get_storage_file()

        # Load existing data
        favorites_data = self._load_favorites_data(storage_file)

        # Update favorite status
        favorites_data[item_id] = is_favorite

        # Save updated data
        with open(storage_file, 'w') as f:
            json.dump(favorites_data, f)

    def load_favorite_status(self, item_id):
        """Load favorite status for an item from storage files."""
        # Check all gr* files for the item
        for file_path in glob.glob(self.favorite_files_pattern):
            favorites_data = self._load_favorites_data(file_path)
            if item_id in favorites_data:
                return favorites_data[item_id]
        return False  # Default to not favorite if not found

    def _get_storage_file(self):
        """Get the appropriate storage file, creating one if none exist."""
        files = glob.glob(self.favorite_files_pattern)
        if not files:
            # Create a new storage file if none exist
            return os.path.join(self.data_dir, "gr1")
        # Use the first available file
        return files[0]

    def _load_favorites_data(self, file_path):
        """Load favorites data from a specific file."""
        if not os.path.exists(file_path):
            return {}

        try:
            with open(file_path, 'r') as f:
                return json.load(f)
        except (json.JSONDecodeError, IOError):
            return {}
