    isTyping: false,
    streamingContent: '',
    conversationId: null,
    cameraCommand: null,
    // Phase 70: Camera ref for viewport context
    cameraRef: null,

    // Phase 61: Pinned files
    pinnedFileIds: [],

    // FIX_109.4: Current chat ID for unified ID system
    currentChatId: null,
    setCurrentChatId: (id) => set({ currentChatId: id }),

    // Phase 65: Grab mode
    grabMode: false,

    // Phase 113.4: Label Championship
    selectedLabelIds: [],
    persistPositions: false,  // OFF by default (Phase 113.3 lesson: persistence = risky without toggle)

    setNodes: (nodesList) => set({
      nodes: Object.fromEntries(nodesList.map(n => [n.id, n])),
      rootPath: nodesList.find(n => n.depth === 0)?.path || null
    }),

    setNodesFromRecord: (nodes) => set({
      nodes,
      rootPath: Object.values(nodes).find(n => n.depth === 0)?.path || null
    }),

    setEdges: (edges) => set({ edges }),

    selectNode: (id) => set({ selectedId: id }),

    hoverNode: (id) => set({ hoveredId: id }),

    highlightNode: (id) => set({ highlightedId: id }),

    // Phase 69: Multi-highlight implementation
    highlightNodes: (ids) => set({ highlightedIds: new Set(ids) }),
    clearHighlights: () => set({ highlightedIds: new Set() }),

    setLoading: (isLoading) => set({ isLoading }),

    setError: (error) => set({ error }),

    setSocketConnected: (isSocketConnected) => set({ isSocketConnected }),

    setDraggingAny: (isDraggingAny) => set({ isDraggingAny }),

    updateNodePosition: (id, position) => set((state) => {
      if (!state.nodes[id]) return state;
      return {
        nodes: {
          ...state.nodes,
          [id]: { ...state.nodes[id], position }
        }
      };
    }),

    // MARKER_111_DRAG: Move node with all children (branch follows)
    moveNodeWithChildren: (id, newPosition) => set((state) => {
      const node = state.nodes[id];
      if (!node) return state;

      const updatedNodes = { ...state.nodes };
      const queue = [id];

      while (queue.length > 0) {
        const currentId = queue.shift()!;
        const currentNode = updatedNodes[currentId];

        if (currentNode) {
          // Update position
          updatedNodes[currentId] = {
            ...currentNode,
            position: {
              x: currentNode.position.x + (newPosition.x - node.position.x),
              y: currentNode.position.y + (newPosition.y - node.position.y),
              z: currentNode.position.z + (newPosition.z - node.position.z)
            }
          };

          // Add children to queue for processing
          if (currentNode.children) {
            queue.push(...currentNode.children);
          }
        }
      }

      return { nodes: updatedNodes };
    }),

    addNode: (node) => set((state) => {
      const newNodes = { ...state.nodes };
      newNodes[node.id] = node;
      return { nodes: newNodes };
    }),

    removeNode: (id) => set((state) => {
      const newNodes = { ...state.nodes };
      delete newNodes[id];

      // Remove from parent's children list
      Object.values(newNodes).forEach(node => {
        if (node.children?.includes(id)) {
          node.children = node.children.filter(childId => childId !== id);
        }
      });

      return { nodes: newNodes };
    }),

    // Legacy chat
    addMessage: (message) => set((state) => ({
      messages: [...state.messages, message]
    })),

    clearMessages: () => set({ messages: [] }),

    // New chat system
    addChatMessage: (msg) => set((state) => ({
      chatMessages: [...state.chatMessages, msg]
    })),

    updateChatMessage: (id, updates) => set((state) => ({
      chatMessages: state.chatMessages.map(msg => 
        msg.id === id ? { ...msg, ...updates } : msg
      )
    })),

    setWorkflowStatus: (status) => set({ currentWorkflow: status }),

    setIsTyping: (typing) => set({ isTyping: typing }),

    appendStreamingContent: (delta) => set((state) => ({
      streamingContent: state.streamingContent + delta
    })),

    clearStreamingContent: () => set({ streamingContent: '' }),

    clearChat: () => set({ 
      chatMessages: [], 
      streamingContent: '', 
      isTyping: false 
    }),

    setConversationId: (id) => set({ conversationId: id }),

    // Camera
    setCameraCommand: (command) => set({ cameraCommand: command }),

    // Phase 70: Camera ref setter
    setCameraRef: (camera) => set({ cameraRef: camera }),

    // Phase 61: Pinned files actions
    togglePinFile: (nodeId) => set((state) => {
      const pinnedIds = new Set(state.pinnedFileIds);
      if (pinnedIds.has(nodeId)) {
        pinnedIds.delete(nodeId);
      } else {
        pinnedIds.add(nodeId);
      }
      return { pinnedFileIds: Array.from(pinnedIds) };
    }),

    pinSubtree: (rootId) => set((state) => {
      const newPinned = new Set(state.pinnedFileIds);

      // Add root and all descendants
      const addToPinned = (nodeId: string) => {
        newPinned.add(nodeId);
        const node = state.nodes[nodeId];
        if (node?.children) {
          node.children.forEach(addToPinned);
        }
      };

      addToPinned(rootId);
      return { pinnedFileIds: Array.from(newPinned) };
    }),

    clearPinnedFiles: () => set({ pinnedFileIds: [] }),

    // Phase 100.2: Set pinned files from backend (for persistence)
    setPinnedFiles: (ids) => set({ pinnedFileIds: ids }),

    // Phase 65: Smart pin based on node type
    pinNodeSmart: (nodeId) => set((state) => {
      const node = state.nodes[nodeId];
      if (!node) return {};

      // Only pin files and folders, not chat nodes
      if (node.type === 'file' || node.type === 'folder') {
        const newPinned = new Set(state.pinnedFileIds);
        newPinned.add(nodeId);
        return { pinnedFileIds: Array.from(newPinned) };
      }

      return {};
    }),

    // Phase 65: Grab mode for Blender-style node movement
    setGrabMode: (enabled) => set({ grabMode: enabled }),

    // Phase 113.1: Persistent Spatial Memory
    savePositions: () => {
      const positions = {};
      Object.entries(get().nodes).forEach(([id, node]) => {
        positions[id] = node.position;
      });
      localStorage.setItem(POSITIONS_STORAGE_KEY, JSON.stringify(positions));
    },

    loadPositions: () => {
      const savedPositions = localStorage.getItem(POSITIONS_STORAGE_KEY);
      if (savedPositions) {
        const positions = JSON.parse(savedPositions);
        set((state) => {
          const updatedNodes = { ...state.nodes };
          Object.entries(positions).forEach(([id, pos]) => {
            if (updatedNodes[id]) {
              updatedNodes[id] = { ...updatedNodes[id], position: pos };
            }
          });
          return { nodes: updatedNodes };
        });
      }
    },

    // Phase 113.4: Label Championship — score-based label selection
    setSelectedLabels: (labelIds) => set({ selectedLabelIds: labelIds }),

    // Phase 113.4: Persist positions toggle (DevPanel control)
    setPersistPositions: (enabled) => set({ persistPositions: enabled }),

    resetLayout: () => set({
      nodes: {},
      edges: [],
      selectedId: null,
      hoveredId: null,
      highlightedId: null,
      highlightedIds: new Set(),
      pinnedFileIds: [],
      chatMessages: [],
      streamingContent: '',
      isTyping: false,
      conversationId: null,
      currentChatId: null,
      currentWorkflow: null,
      cameraCommand: null,
      cameraRef: null
    }),

    // MARKER_123.2B: Phase 123 - Activity heat score for glow effect
    setNodeHeatScore: (nodeId, intensity) => set((state) => {
      if (!state.nodes[nodeId]) return state;
      return {
        nodes: {
          ...state.nodes,
          [nodeId]: { 
            ...state.nodes[nodeId], 
            heatScore: intensity 
          }
        }
      };
    })
  }))
